  1	import React, { FC, useState } from 'react';
  2	
  3	import { produceVMDevices } from '@catalog/utils/WizardVMContext';
  4	import {
  5	  V1GPU,
  6	  V1HostDevice,
  7	  V1VirtualMachine,
  8	  V1VirtualMachineInstance,
  9	} from '@kubevirt-ui/kubevirt-api/kubevirt';
 10	import ModalPendingChangesAlert from '@kubevirt-utils/components/PendingChanges/ModalPendingChangesAlert/ModalPendingChangesAlert';
 11	import TabModal from '@kubevirt-utils/components/TabModal/TabModal';
 12	import { generatePrettyName, isEmpty } from '@kubevirt-utils/utils/utils';
 13	import { Button, ButtonVariant, Form, FormGroup, Grid, GridItem } from '@patternfly/react-core';
 14	import { MinusCircleIcon, PlusCircleIcon } from '@patternfly/react-icons';
 15	
 16	import DeviceNameSelect from '../form/DeviceNameSelect';
 17	import NameFormField from '../form/NameFormField';
 18	import useHCPermittedHostDevices from '../hooks/useHCPermittedHostDevices';
 19	import { HARDWARE_DEVICE_TYPE, HardwareDeviceModalRow } from '../utils/constants';
 20	import { getInitialDevices } from '../utils/helpers';
 21	
 22	import HardwareDeviceModalDescription from './HardwareDeviceModalDescription';
 23	
 24	import '../hardware-devices-table.scss';
 25	
 26	type HardwareDevicesModalProps = {
 27	  btnText: string;
 28	  headerText: string;
 29	  initialDevices: V1GPU[] | V1HostDevice[];
 30	  isOpen: boolean;
 31	  onClose: () => void;
 32	  onSubmit: (updatedVM: V1VirtualMachine) => Promise<V1VirtualMachine | void>;
 33	  type: HARDWARE_DEVICE_TYPE.GPUS | HARDWARE_DEVICE_TYPE.HOST_DEVICES;
 34	  vm: V1VirtualMachine;
 35	  vmi?: V1VirtualMachineInstance;
 36	};
 37	
 38	const HardwareDevicesModal: FC<HardwareDevicesModalProps> = ({
 39	  btnText,
 40	  headerText,
 41	  initialDevices,
 42	  isOpen,
 43	  onClose,
 44	  onSubmit,
 45	  type,
 46	  vm,
 47	  vmi,
 48	}) => {
 49	  const [devices, setDevices] = useState<HardwareDeviceModalRow[]>(
 50	    getInitialDevices(initialDevices, type),
 51	  );
 52	  const { permittedHostDevices } = useHCPermittedHostDevices();
 53	
 54	  const onAddDevice = () => {
 55	    setDevices((listDevices) => [
 56	      ...listDevices,
 57	      { deviceIndex: devices.length, deviceName: '', name: generatePrettyName(type) },
 58	    ]);
 59	  };
 60	
 61	  const onDelete = (index: number) => {
 62	    setDevices((listDevices) =>
 63	      listDevices
 64	        ?.filter((device) => device?.deviceIndex !== index)
 65	        .map((device, deviceIndex) => ({ ...device, deviceIndex })),
 66	    );
 67	  };
 68	
 69	  const disableSubmit = devices.some((device) => isEmpty(device?.deviceName));
 70	
 71	  const toK8sDevice = ({ deviceName, name }: HardwareDeviceModalRow): V1GPU | V1HostDevice => ({
 72	    deviceName,
 73	    name,
 74	  });
 75	
 76	  const updatedVM = produceVMDevices(vm, (vmDraft: V1VirtualMachine) => {
 77	    vmDraft.spec.template.spec.domain.devices[type] = isEmpty(devices)
 78	      ? null
 79	      : devices.map(toK8sDevice);
 80	  });
 81	
 82	  return (
 83	    <TabModal
 84	      headerText={headerText}
 85	      isDisabled={disableSubmit}
 86	      isOpen={isOpen}
 87	      obj={updatedVM}
 88	      onClose={onClose}
 89	      onSubmit={onSubmit}
 90	    >
 91	      {vmi && <ModalPendingChangesAlert />}
 92	      <Form>
 93	        <HardwareDeviceModalDescription type={type} />
 94	        {devices.map(({ deviceIndex, deviceName, name }) => (
 95	          <Grid hasGutter key={deviceIndex}>
 96	            <GridItem span={5}>
 97	              <NameFormField
 98	                setName={(newName: string) => {
 99	                  setDevices((prevDevices) => {
100	                    const newDevices = [...prevDevices];
101	                    newDevices[deviceIndex] = { ...newDevices[deviceIndex], name: newName };
102	                    return newDevices;
103	                  });
104	                }}
105	                index={deviceIndex}
106	                name={name}
107	              />
108	            </GridItem>
109	            <GridItem span={5}>
110	              <DeviceNameSelect
111	                setDeviceName={(newDeviceName: string) => {
112	                  setDevices((prevDevices) => {
113	                    const newDevices = [...prevDevices];
114	                    newDevices[deviceIndex] = {
115	                      ...newDevices[deviceIndex],
116	                      deviceName: newDeviceName,
117	                    };
118	                    return newDevices;
119	                  });
120	                }}
121	                deviceName={deviceName}
122	                index={deviceIndex}
123	                permittedHostDevices={permittedHostDevices}
124	              />
125	            </GridItem>
126	            <GridItem className="hardware-devices-form-button" span={2}>
127	              <Button onClick={() => onDelete(deviceIndex)} variant={ButtonVariant.plain}>
128	                <MinusCircleIcon />
129	              </Button>
130	            </GridItem>
131	          </Grid>
132	        ))}
133	        <FormGroup fieldId="add-button">
134	          <Button
135	            className="pf-m-link--align-left"
136	            icon={<PlusCircleIcon />}
137	            onClick={onAddDevice}
138	            variant="link"
139	          >
140	            {btnText}
141	          </Button>
142	        </FormGroup>
143	      </Form>
144	    </TabModal>
145	  );
146	};
147	
148	export default HardwareDevicesModal;

